class LmdbSketchJoinOptimizerMinusRewriteTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void reordersChainedMinusWhenLaterIndependentRhsIsCheaper() {
		StatementPattern left = statementPattern("item", "type", "type");
		StatementPattern expensive = statementPattern("item", "expensive", "expensiveMatch");
		StatementPattern cheap = statementPattern("item", "cheap", "cheapMatch");
		QueryRoot root = new QueryRoot(new Difference(new Difference(left, expensive), cheap));

		new LmdbSketchJoinOptimizer(MinusCostModel.standard(), false).optimize(root, null, null);

		Difference outer = assertInstanceOf(Difference.class, root.getArg(), () -> root.getArg().toString());
		Difference inner = assertInstanceOf(Difference.class, outer.getLeftArg(), () -> root.getArg().toString());
		assertContainsPredicate(inner.getRightArg(), "cheap");
		assertContainsPredicate(outer.getRightArg(), "expensive");
	}

	@Test
	void distributesUnionMinusWhenDistributedAlternativeCostsLess() {
		StatementPattern first = statementPattern("item", "first", "value");
		StatementPattern second = statementPattern("item", "second", "value");
		StatementPattern right = statementPattern("item", "blocked", "blockedBy");
		QueryRoot root = new QueryRoot(new Difference(new Union(first, second), right));

		new LmdbSketchJoinOptimizer(MinusCostModel.standard(), false).optimize(root, null, null);

		Union union = assertInstanceOf(Union.class, root.getArg(), () -> root.getArg().toString());
		assertInstanceOf(Difference.class, union.getLeftArg(), () -> root.getArg().toString());
		assertInstanceOf(Difference.class, union.getRightArg(), () -> root.getArg().toString());
	}

	@Test
	void combinesRepeatedMinusRightSidesWhenUnionRhsCostsLess() {
		StatementPattern left = statementPattern("item", "type", "type");
		StatementPattern first = statementPattern("item", "expensive", "expensiveMatch");
		StatementPattern second = statementPattern("item", "cheap", "cheapMatch");
		QueryRoot root = new QueryRoot(new Difference(new Difference(left, first), second));

		new LmdbSketchJoinOptimizer(MinusCostModel.preferCombinedRhs(), false).optimize(root, null, null);

		Difference difference = assertInstanceOf(Difference.class, root.getArg(), () -> root.getArg().toString());
		assertContainsPredicate(difference.getLeftArg(), "type");
		assertInstanceOf(Union.class, difference.getRightArg(), () -> root.getArg().toString());
	}

	@Test
	void usesBoundRightSidePlanningWhenPhysicalMinusProbeIsCheaper() {
		StatementPattern left = statementPattern("item", "type", "type");
		StatementPattern right = statementPattern("item", "blocked", "blockedBy");
		QueryRoot root = new QueryRoot(new Difference(left, right));

		new LmdbSketchJoinOptimizer(MinusCostModel.standard(), false).optimize(root, null, null);

		assertTrue(right.getStringMetricPlanned("optimizer.minusBoundRhsPlanning")
				.startsWith("selected=anchored, originalWork=100, anchoredWork=2"));
		assertInstanceOf(Difference.class, root.getArg(), () -> root.getArg().toString());
	}

	@Test
	void skipsMinusAlternativesForScopeChangingRightSide() {
		StatementPattern first = statementPattern("item", "first", "firstValue");
		StatementPattern second = statementPattern("item", "second", "secondValue");
		StatementPattern servicePattern = statementPattern("item", "blocked", "blockedBy");
		Service service = new Service(Var.of("serviceRef", VF.createIRI("urn:service")), servicePattern,
				"SERVICE <urn:service> { ?item <urn:blocked> ?blockedBy }", null, null, false);
		QueryRoot root = new QueryRoot(new Difference(new Union(first, second), service));

		new LmdbSketchJoinOptimizer(MinusCostModel.standard(), false).optimize(root, null, null);

		assertInstanceOf(Difference.class, root.getArg(), () -> root.getArg().toString());
		assertNull(service.getStringMetricPlanned("optimizer.minusBoundRhsPlanning"));
	}

	@Test
	void skipsMinusAlternativesForExtensionRightSide() {
		StatementPattern left = statementPattern("item", "type", "type");
		Extension extension = new Extension(statementPattern("item", "blocked", "blockedBy"),
				new ExtensionElem(new Var("blockedBy"), "derivedBlockedBy"));
		QueryRoot root = new QueryRoot(new Difference(left, extension));

		new LmdbSketchJoinOptimizer(MinusCostModel.standard(), false).optimize(root, null, null);

		assertInstanceOf(Difference.class, root.getArg(), () -> root.getArg().toString());
		assertNull(extension.getStringMetricPlanned("optimizer.minusBoundRhsPlanning"));
	}

	private static StatementPattern statementPattern(String subjectName, String predicateName, String objectName) {
		return new StatementPattern(new Var(subjectName), new Var(predicateName, VF.createIRI("urn:" + predicateName)),
				new Var(objectName));
	}

	private static void assertContainsPredicate(TupleExpr tupleExpr, String predicateName) {
		assertTrue(tupleExpr.toString().contains("urn:" + predicateName), () -> tupleExpr.toString());
	}

	private static final class MinusCostModel extends EvaluationStatistics implements JoinFactorCostModel {

		private final double combinedRhsWork;

		private MinusCostModel(double combinedRhsWork) {
			this.combinedRhsWork = combinedRhsWork;
		}

		private static MinusCostModel standard() {
			return new MinusCostModel(220.0d);
		}

		private static MinusCostModel preferCombinedRhs() {
			return new MinusCostModel(20.0d);
		}

		@Override
		public Optional<JoinFactorCostModel.FactorCostEstimate> estimateFactorCost(TupleExpr factor,
				Set<String> currentlyBoundVars) {
			if (isUnionOfDifferences(factor)) {
				return estimate(20.0d, 20.0d);
			}
			if (factor instanceof Difference difference) {
				if (difference.getLeftArg() instanceof Union) {
					return estimate(200.0d, 20.0d);
				}
				if (difference.getRightArg() instanceof Union) {
					return estimate(combinedRhsWork, 20.0d);
				}
				if (difference.getLeftArg()instanceof Difference inner) {
					String innerPredicate = firstPredicateName(inner.getRightArg());
					String outerPredicate = firstPredicateName(difference.getRightArg());
					if ("expensive".equals(innerPredicate) && "cheap".equals(outerPredicate)) {
						return estimate(150.0d, 20.0d);
					}
					if ("cheap".equals(innerPredicate) && "expensive".equals(outerPredicate)) {
						return estimate(30.0d, 20.0d);
					}
				}
				return estimate(110.0d, 20.0d);
			}
			if (factor instanceof StatementPattern statementPattern) {
				String predicateName = predicateName(statementPattern);
				if ("type".equals(predicateName) || "first".equals(predicateName) || "second".equals(predicateName)) {
					return estimate(10.0d, 1000.0d);
				}
				if ("blocked".equals(predicateName)) {
					return estimate(currentlyBoundVars.contains("item") ? 2.0d : 100.0d, 10.0d);
				}
				if ("cheap".equals(predicateName)) {
					return estimate(10.0d, 10.0d);
				}
				if ("expensive".equals(predicateName)) {
					return estimate(100.0d, 10.0d);
				}
			}
			return estimate(50.0d, 20.0d);
		}

		private static Optional<JoinFactorCostModel.FactorCostEstimate> estimate(double workRows, double outputRows) {
			return Optional.of(new JoinFactorCostModel.FactorCostEstimate(workRows, outputRows));
		}

		private static boolean isUnionOfDifferences(TupleExpr tupleExpr) {
			return tupleExpr instanceof Union union
					&& union.getLeftArg() instanceof Difference
					&& union.getRightArg() instanceof Difference;
		}

		private static String firstPredicateName(TupleExpr tupleExpr) {
			if (tupleExpr instanceof StatementPattern statementPattern) {
				return predicateName(statementPattern);
			}
			if (tupleExpr instanceof Difference difference) {
				return firstPredicateName(difference.getRightArg());
			}
			if (tupleExpr instanceof Union union) {
				return firstPredicateName(union.getLeftArg());
			}
			if (tupleExpr instanceof LeftJoin leftJoin) {
				return firstPredicateName(leftJoin.getRightArg());
			}
			return "";
		}

		private static String predicateName(StatementPattern statementPattern) {
			String value = statementPattern.getPredicateVar().getValue().stringValue();
			int offset = value.lastIndexOf(':');
			return offset >= 0 ? value.substring(offset + 1) : value;
		}
	}
}
